html:
{%- macro add_header(page_num, max_pages, doc, letter_head, no_letterhead) -%}
{% if letter_head and not no_letterhead %}
<div style="height:23mm;" class="letter-head">
  {{ letter_head }}
</div>
{% endif %}
{% if max_pages > 1 %}
<p class="text-right">
  {{ _("Page #{0} of {1}").format(page_num, max_pages) }}
</p>
{% endif %}
{%- endmacro -%}

<div id="header-html" class="hidden-pdf">
  {{ add_header(0,1,doc,letter_head, no_letterhead) }}
</div>

<div id="footer-html" class="visible-pdf">
{% if not no_letterhead and footer %}
<div class="letter-head-footer">
  {{ footer }}
</div>
{% endif %}
<p class="text-center small page-number visible-pdf" align="center">
  {{ _("Page {0} of {1}").format('<span class="page"></span>', '<span class="topage"></span>') }}
</p>
</div>

<style>
#footer-html { display:none; }

body {
    font-family: Arial, sans-serif;
    margin: 5px;
}

table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 0px;
    margin-bottom: 0px;
    font-size: 10px;
}

table, th, td {
    border: 1px solid #aaa;
}

th, td {
    padding: 8px;
    text-align: center;
}

.no-border {
    border: none !important;
}

@media print {
    #footer-html {
        display:block;
        margin-top:10mm;
    }
}
</style>

<div class="row" style="display: flex; justify-content: center; align-items: center; margin: 0; padding: 0; position: relative;">
    <div class="col-xs-12" style="text-align: left; padding: 0; margin: 0; flex: 1;">
        <h2 style="margin-top: 0px; text-align:center;">
            <strong>Delivery Challan</strong>
        </h2>
    </div>
</div>

<div class="details">
<div class="row" style="margin: 0; padding: 0;">
<div class="col-xs-6" style="padding: 0; margin-top: -6px;">

<p style="margin: 10px 0 0 0; font-size: 11px;">
<strong> Delivery To: </strong><br>
<strong>Party Name: </strong> {{doc.customer}}<br>
<strong> Delivery Address: </strong>{{doc.address_display}}
</p>

<p style="margin: 0px;font-size: 11px;">
<strong>Kind Attn.: </strong>{{ doc.custom_kind_attn_of or ""}}<br>
<strong>Phone: </strong>{{ doc.custom_contact_no or ""}}<br>
</p>

</div>

<div class="col-xs-6" style="padding: 0; margin: 0;">
<p style="margin: 0 0 0 130px; font-size: 11px;">
<strong>Purpose of Delivery: </strong>{{doc.custom_purpose_of_delivery or ""}}<br>
<strong>Delivery Challan No.:  </strong>{{ doc.name }}<br>
<strong>Document Date:  </strong>{{frappe.utils.get_datetime(doc.po_date).strftime("%d-%m-%Y")}}<br>
<strong>Project No:  </strong>{{doc.project}}
</p>
</div>
</div>
</div>

<table style="margin: 10px 0 0 0; border-collapse: collapse; width: 100%; font-size: 10px;">
<thead>
<tr>
<th style="width: 3%; font-size: 9px;">Sr No.</th>
<th style="width: 17%; font-size: 9px;">Material Code</th>
<th style="width: 29%; font-size: 9px;">Material Description</th>
<th style="width:8%; font-size: 9px;">HSN</th>
<th style="width: 6%; font-size: 9px;">Quantity</th>
<th style="width: 6%; font-size: 9px;">UOM</th>
<th style="width: 10%; font-size: 9px;">Unit Rate </th>
<th style="width: 11%; font-size: 9px;">Amount</th>
<th style="width: 10%; font-size: 9px;">Remark</th>
</tr>
</thead>

<tbody>
{% for row in doc.items %}
<tr>
<td style="font-size: 11px;">{{ loop.index }}</td>
<td style="font-size: 11px; text-align: left;">{{row.item_code}}</td>
<td style="font-size: 11px; text-align: left;">{{ row.item_name }}</td>
<td style="font-size: 11px;">{{ row.gst_hsn_code }}</td>
<td style="font-size: 11px;">{{ row.qty }}</td>
<td style="font-size: 11px;">{{row.uom}}</td>
<td style="font-size: 11px;">₹ {{row.rate}}</td>
<td style="font-size: 11px;">₹ {{row.amount}}</td>
<td style="font-size: 11px;">{{ row.custom_remark or "" }}</td>
</tr>
{% endfor %}

<tr>
<td></td>
<td style="text-align: left;"><b>Total</b></td>
<td></td>
<td></td>
<td>{{ doc.total_qty }}</td>
<td></td>
<td></td>
<td>₹ {{ doc.base_total }}</td>
<td></td>
</tr>
</tbody>
</table>

{% if doc.instructions %}
<p style="margin:4px;font-size: 11px;margin-left:1px;">
<b>Remark: </b>{{ doc.instructions }}
</p>
{% else %}
<p style="margin:4px;font-size: 11px;">
<b>&nbsp;Remark: </b>
</p>
{% endif %}

<br><br>

{% if doc.terms %}
<p style="margin: 0px;font-size: 11px;">
<b>Terms: </b>
</p>

<div style="margin: 0px;font-size: 11px;">
{{ doc.terms }}
</div>

{% else %}
<p style="margin: 0px;font-size: 11px;">
<b>Terms: </b>
</p>
{% endif %}

<table style="width: 30%; float:right;" class="no-border">
<tr style="text-align:left;">
<td style="text-align:left;">
<b>Authorized Signatory</b><br><br><br><br>
<b>Prepared by: </b><br>
<b>Designation: </b>
</td>
</tr>
</table>
